export interface Element {
  id: number;
  name: string;
  alias: string;
  description: string;
  category: string;
}

import { Injectable } from '@nestjs/common';
import { Element } from './interfaces/element.interface';
import * as mockElements from './data/elements.json';

@Injectable()
export class ElementsService {
  // Cast JSON import to Element[] interface
  private readonly elements: Element[] = Array.from(mockElements) as Element[];

  findAll(): Element[] {
    return this.elements;
  }
}

import { Controller, Get } from '@nestjs/common';
import { ElementsService } from './elements.service';
import { Element } from './interfaces/element.interface';

@Controller('elements')
export class ElementsController {
  constructor(private readonly elementsService: ElementsService) {}

  @Get()
  findAll(): Element[] {
    return this.elementsService.findAll();
  }
}

import { ExceptionFilter, Catch, ArgumentsHost, HttpException, HttpStatus, Logger } from '@nestjs/common';
import { Request, Response } from 'express';

@Catch()
export class HttpExceptionFilter implements ExceptionFilter {
  private readonly logger = new Logger(HttpExceptionFilter.name);

  catch(exception: unknown, host: ArgumentsHost) {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();

    let status = HttpStatus.INTERNAL_SERVER_ERROR;
    let message = 'Internal server error';

    if (exception instanceof HttpException) {
      status = exception.getStatus();
      const exceptionResponse = exception.getResponse();
      message = typeof exceptionResponse === 'object' && exceptionResponse !== null && 'message' in exceptionResponse
        ? (exceptionResponse as any).message
        : exception.message;
    } else if (exception instanceof Error) {
      message = exception.message;
    }

    // Log the error
    this.logger.error(
      `HTTP Status: ${status} Error Message: ${JSON.stringify(message)} Path: ${request.url}`
    );

    // Return structured JSON error response
    response.status(status).json({
      statusCode: status,
      timestamp: new Date().toISOString(),
      path: request.url,
      message: status === HttpStatus.NOT_FOUND ? `Ruta inexistente: ${request.url}` : message,
    });
  }
}

import { NestFactory } from '@nestjs/core';
import { AppModule } from './app.module';
import { HttpExceptionFilter } from './common/filters/http-exception.filter';
import { Logger } from '@nestjs/common';

async function bootstrap() {
  const logger = new Logger('Bootstrap');
  const app = await NestFactory.create(AppModule);

  // Set global API prefix to match /api/v1/...
  app.setGlobalPrefix('api/v1');

  // Enable CORS to allow request communication from Angular 19 (http://localhost:4200)
  app.enableCors({
    origin: 'http://localhost:4200',
    methods: 'GET,HEAD,PUT,PATCH,POST,DELETE,OPTIONS',
    credentials: true,
  });

  // Apply global exception filter for clean error responses (e.g. invalid routes)
  app.useGlobalFilters(new HttpExceptionFilter());

  const port = 3001;
  await app.listen(port);
  logger.log(`Server is running at: http://localhost:${port}/api/v1`);
}
bootstrap();

